  "intent": "check_and_fix",
  "intent_description": "R2 Serial0/1/1 went from oper=up to oper=lower-layer-down while admin remains up; R3 Serial0/1/1 went from oper=up to oper=down and is administratively down. Impact: loss of serial link between R2 and R3. Desired outcome: restore the serial link (oper up) by reconciling administrative state.",
  "target": "R2 Serial0/1/1 and R3 Serial0/1/1",
  "needs_fix": true,
  "plan": {
    "problem": "Serial link between R2 and R3 is down: R2 Serial0/1/1 oper=lower-layer-down (admin up); R3 Serial0/1/1 oper=down (admin down). Likely cause: R3 interface is administratively shut.",
    "fix_summary": "Remove administrative shutdown on R3 Serial0/1/1 (set admin up) to restore the link. If link does not return to oper up, perform further diagnostics (log review, provider circuit checks).",
    "plan_steps": [
      {
        "id": 1,
        "device": "router3",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/1",
        "parameters": [
          "admin_state=up"
        ]
      }
    ]
  }
}

